package com.jc.intelligence.production.search.v1;

import com.jc.intelligence.contract.v1.version.PolicyVersion;import com.jc.intelligence.contract.v1.version.SchemaVersion;import java.time.Duration;import java.time.Instant;import java.util.List;import java.util.Objects;
public record SearchProjectionQueryV1(List<String> queryTerms,String regionReference,int maximumCandidateCount,SchemaVersion projectionSchemaVersion,PolicyVersion eligibilityPolicyVersion,Instant referenceTime,Duration maximumStaleness){
 public SearchProjectionQueryV1{queryTerms=List.copyOf(Objects.requireNonNull(queryTerms,"queryTerms"));for(String term:queryTerms)if(term==null||term.isBlank()||term.length()>128)throw new IllegalArgumentException("query term invalid");if(regionReference!=null&&!regionReference.matches("[a-z0-9][a-z0-9-]{0,79}"))throw new IllegalArgumentException("regionReference invalid");if(maximumCandidateCount<1||maximumCandidateCount>1000)throw new IllegalArgumentException("maximumCandidateCount must be 1..1000");Objects.requireNonNull(projectionSchemaVersion,"projectionSchemaVersion");Objects.requireNonNull(eligibilityPolicyVersion,"eligibilityPolicyVersion");Objects.requireNonNull(referenceTime,"referenceTime");Objects.requireNonNull(maximumStaleness,"maximumStaleness");if(maximumStaleness.isZero()||maximumStaleness.isNegative()||maximumStaleness.compareTo(Duration.ofDays(30))>0)throw new IllegalArgumentException("maximumStaleness invalid");}
}
